print("[DEFINE_WORKER: \"Process PDF Forms\" ProcessPdfForms]\n[INPUTS]\n    REQUIRED <REF> input_pdf </REF>\n    OPTIONAL <REF> field_info </REF>\n    OPTIONAL <REF> images_dir </REF>\n    OPTIONAL <REF> field_values_json </REF>\n    OPTIONAL <REF> form_structure </REF>\n    OPTIONAL <REF> fields_json </REF>\n    OPTIONAL <REF> verify_images_dir </REF>\n[END_INPUTS]\n[OUTPUTS]\n    OPTIONAL <REF> has_fillable </REF>\n    OPTIONAL <REF> analyzed_structure </REF>\n    OPTIONAL <REF> bounding_boxes_checked </REF>\n    OPTIONAL <REF> filled_pdf </REF>\n[END_OUTPUTS]\n[MAIN_FLOW]\n    [SEQUENTIAL_BLOCK]\n        COMMAND-1 [CALL CheckFillableFields WITH {file_path: <REF> input_pdf </REF>} RESPONSE has_fillable: boolean]\n    [END_SEQUENTIAL_BLOCK]\n    DECISION-1 [IF has_fillable == true]\n        [SEQUENTIAL_BLOCK]\n            COMMAND-2 [CALL ExtractFormFieldInfo WITH {input_pdf: <REF> input_pdf </REF>, output_json: <REF> field_info </REF>}]\n            COMMAND-3 [CALL ConvertPdfToImages WITH {file_pdf: <REF> input_pdf </REF>, output_directory: <REF> images_dir </REF>}]\n            COMMAND-4 [COMMAND Create a JSON file with values to be entered for each field RESULT field_values_json: text]\n            COMMAND-5 [CALL FillFillableFields WITH {input_pdf: <REF> input_pdf </REF>, field_values_json: <REF> field_values_json </REF>, output_pdf: <REF> filled_pdf </REF>}]\n        [END_SEQUENTIAL_BLOCK]\n    [ELSE]\n        [SEQUENTIAL_BLOCK]\n            COMMAND-6 [CALL ExtractFormStructure WITH {input_pdf: <REF> input_pdf </REF>, output_json: <REF> form_structure </REF>}]\n            COMMAND-7 [COMMAND Analyze the extracted form structure to identify labels, rows, and field columns RESULT analyzed_structure: text]\n            COMMAND-8 [COMMAND Calculate entry coordinates for each field based on the extracted structure RESULT fields_json: text]\n            COMMAND-9 [CALL CheckBoundingBoxes WITH {fields_json: <REF> fields_json </REF>} RESPONSE bounding_boxes_checked: text]\n            COMMAND-10 [CALL FillPdfFormWithAnnotations WITH {input_pdf: <REF> input_pdf </REF>, fields_json: <REF> fields_json </REF>, output_pdf: <REF> filled_pdf </REF>}]\n        [END_SEQUENTIAL_BLOCK]\n    [END_IF]\n    [SEQUENTIAL_BLOCK]\n        COMMAND-11 [CALL ConvertPdfToImages WITH {file_pdf: <REF> filled_pdf </REF>, output_directory: <REF> verify_images_dir </REF>}]\n    [END_SEQUENTIAL_BLOCK]\n[END_MAIN_FLOW]\n[ALTERNATIVE_FLOW: If the PDF doesn't have fillable form fields]\n    [SEQUENTIAL_BLOCK]\n        COMMAND-12 [CALL ExtractFormStructure WITH {input_pdf: <REF> input_pdf </REF>, output_json: <REF> form_structure </REF>}]\n        COMMAND-13 [INPUT DISPLAY \"Use visual analysis to identify form fields and estimate their coordinates\" VALUE visual_analysis: text]\n        COMMAND-14 [INPUT DISPLAY \"Refine field coordinates using cropped images\" VALUE refined_coordinates: text]\n    [END_SEQUENTIAL_BLOCK]\n[END_ALTERNATIVE_FLOW]\n[END_WORKER]")